@pytest.fixture
def clean_cache():
    # Nos aseguramos que el directorio de caché está limpio antes y después de cada test
    cache_dir = CACHE_DIR / APP_NAME
    if cache_dir.exists():
        shutil.rmtree(cache_dir)

    yield

    if cache_dir.exists():
        shutil.rmtree(cache_dir)


@pytest.fixture
def cache_factory():
    def _make_cache_url(app_name=APP_NAME, obsolescence=OBSOLESCENCE):
        return CacheURL(app_name=app_name, obsolescence=obsolescence)

    return _make_cache_url


@pytest.fixture
def hash_url():
    def _make_hash_url(url):
        return md5(url.encode("utf-8")).hexdigest()

    return _make_hash_url


@pytest.fixture
def mock_responses():
    with responses.RequestsMock(assert_all_requests_are_fired=False) as rsps:
        for test_case in TEST_CASES:
            url, content = test_case.values
            rsps.add(responses.GET, url, body=content, status=200)
        yield rsps


def test_cache_url_properties(clean_cache, cache_factory):
    cache = cache_factory()
    assert (
        repr(cache) == f"CacheURL(app_name='{APP_NAME}', obsolescence={OBSOLESCENCE})"
    )
    assert str(cache) == f"La caché de '{APP_NAME}' contiene 0 archivos."

    assert cache.app_name == APP_NAME
    assert cache.obsolescence == OBSOLESCENCE
    assert cache.cache_dir == str(CACHE_DIR / APP_NAME)


@pytest.mark.parametrize(
    "url, content",
    TEST_CASES,
)
def test_cache_url_load(clean_cache, cache_factory, mock_responses, url, content):
    cache = cache_factory()
    cache.get(url)
    assert cache.load(url) == content


@responses.activate
def test_cache_url_http_error(clean_cache, cache_factory):
    # Ver: https://developer.mozilla.org/es/docs/Web/HTTP/Reference/Status/418
    url = "https://fake.com"
    responses.get(url, status=418)
    cache = cache_factory()
    with pytest.raises(
        HTTPError,
        match=f"418 Client Error: I'm a Teapot for url: {url}",
    ):
        cache.get(url)


@pytest.mark.parametrize(
    "url, content",
    TEST_CASES[:1],
)
def test_cache_exists(clean_cache, cache_factory, mock_responses, url, content):
    cache = cache_factory()
    assert not cache.exists(url)
    cache.get(url)
    assert cache.exists(url)


@pytest.mark.parametrize(
    "url, content",
    TEST_CASES[:1],
)
def test_cache_how_old(
    clean_cache, cache_factory, hash_url, mock_responses, url, content
):
    cache = cache_factory()
    name = hash_url(url)
    with pytest.raises(CacheError, match=f"El archivo de caché '{name}' no existe."):
        cache.how_old(url)

    cache.get(url)
    age = cache.how_old(url)
    assert isinstance(age, float)
    assert age >= 0


@pytest.mark.parametrize(
    "url, content",
    TEST_CASES[:1],
)
def test_cache_delete(clean_cache, cache_factory, mock_responses, url, content):
    cache = cache_factory()
    cache.get(url)
    assert str(cache) == f"La caché de '{APP_NAME}' contiene 1 archivo."

    cache.delete(url)
    assert str(cache) == f"La caché de '{APP_NAME}' contiene 0 archivos."

    # No lanza un error aunque la caché de la aplicación ya esté vacía
    cache.delete(url)
